/** @typedef {{ reason?: string, section?: string, actor?: string, source?: string, note?: string }} ConfigSnapshotMeta */
/** @typedef {{ id?: string, name?: string, type?: string, content?: string, savedAt?: string, updatedAt?: string, createdAt?: string, actor?: string, source?: string, requestHost?: string, preferredFallback?: boolean }} DnsRecordHistoryEntryLike */
