/** @typedef {BaseRevisionMeta & { count?: number, indexHash?: string, fullIndexHash?: string }} ExtendedRevisionMeta */
/** @typedef {RequestInit & { cf?: { cacheEverything: boolean, cacheTtl: number } }} WorkerRequestInit */
/** @typedef {Response & { webSocket?: unknown }} UpgradeableResponse */
/** @typedef {Error & { code?: string, status?: number, details?: any }} AppError */
/** @typedef {{ kv?: { namespaceTitle?: string }, d1?: { databaseName?: string } }} CloudflareQuotaResourceMeta */
/** @typedef {{ planClass?: string, planLabel?: string, periodLabel?: string, usageModel?: string, resourceMeta?: CloudflareQuotaResourceMeta }} CloudflareQuotaPlanProfileLike */
/** @typedef {{ payload?: any, cachedAt?: number, expiresAt?: number, updatedAt?: number, stale?: boolean, source?: string, error?: unknown }} CloudflareRuntimeCacheStateLike */
/** @typedef {{ namespaceTitle?: string, readCount?: number, writeCount?: number, storageBytes?: number, deleteCount?: number, listCount?: number }} CloudflareKvUsagePayload */
/** @typedef {{ databaseName?: string, rowsRead?: number, rowsWritten?: number, fileSizeBytes?: number, readQueries?: number, writeQueries?: number }} CloudflareD1UsagePayload */
/** @typedef {{ targetUrl: URL, originText: string, normalizedBasePath: string, absoluteBasePrefix: string }} TargetRecord */
/** @typedef {{ baseHeaderEntries: Array<[string, string]>, hasOriginHeader: boolean, hasRefererHeader: boolean, adminCustomHasOrigin: boolean, adminCustomHasReferer: boolean, refererOrigin: string, refererPathAndSearch: string, isHotMediaRequest: boolean }} ProxyTransportTemplate */
/** @typedef {{ match: (...args: any[]) => Promise<any>, put: (...args: any[]) => Promise<any> }} WorkerDefaultCacheLike */
/** @typedef {{ caches?: { default?: WorkerDefaultCacheLike | null } | null }} WorkerGlobalWithCachesLike */

