function formatCount(value) {
  const numericValue = Number(value);
  if (!Number.isFinite(numericValue)) return "0";
  return Math.max(0, Math.round(numericValue)).toLocaleString("en-US");
}

function clampCloudflareQuotaPercent(value) {
  const numericValue = Number(value);
  if (!Number.isFinite(numericValue) || numericValue <= 0) return 0;
  if (numericValue >= 100) return 100;
  return Math.max(0, Math.round(numericValue * 10) / 10);
}

function getCloudflareQuotaMetricTone(rawPercent = 0) {
  const numericValue = Number(rawPercent);
  if (!Number.isFinite(numericValue) || numericValue <= 0) return "slate";
  if (numericValue >= 90) return "danger";
  if (numericValue >= 70) return "warning";
  return "success";
}

function normalizeCloudflareUsageModel(value = "") {
  const usageModel = String(value || "").trim().toLowerCase();
  return usageModel || "bundled";
}

function normalizeCloudflareQuotaPlanOverride(value = "") {
  const normalizedValue = String(value || "").trim().toLowerCase();
  if (normalizedValue === "paid") return "paid";
  if (normalizedValue === "free") return "free";
  return "";
}

function resolveCloudflareQuotaPlanProfileFromUsageModel(value = "") {
  const usageModel = normalizeCloudflareUsageModel(value);
  if (usageModel === "standard" || usageModel === "unbound") {
    return {
      ...CLOUDFLARE_RUNTIME_PLAN_LIMITS.paid,
      usageModel
    };
  }
  return {
    ...CLOUDFLARE_RUNTIME_PLAN_LIMITS.free,
    usageModel
  };
}

function resolveCloudflareQuotaPlanProfile(options = {}) {
  const planOverride = normalizeCloudflareQuotaPlanOverride(options?.override);
  if (planOverride) {
    return {
      ...getCloudflareQuotaLimitProfile(planOverride),
      usageModel: normalizeCloudflareUsageModel(options?.usageModel),
      override: planOverride
    };
  }
  return {
    ...resolveCloudflareQuotaPlanProfileFromUsageModel(options?.usageModel),
    override: ""
  };
}

function getCloudflareQuotaLimitProfile(planClass = "free") {
  const normalizedPlanClass = String(planClass || "").trim().toLowerCase() === "paid" ? "paid" : "free";
  return CLOUDFLARE_RUNTIME_PLAN_LIMITS[normalizedPlanClass] || CLOUDFLARE_RUNTIME_PLAN_LIMITS.free;
}

async function resolveCloudflareQuotaPlanProfileForConfig(runtimeConfig = {}) {
  const sanitizedConfig = sanitizeRuntimeConfig(isPlainObject(runtimeConfig) ? runtimeConfig : {});
  const planOverride = normalizeCloudflareQuotaPlanOverride(sanitizedConfig.cfQuotaPlanOverride);
  if (planOverride) {
    return resolveCloudflareQuotaPlanProfile({ override: planOverride });
  }
  const accountId = String(sanitizedConfig.cfAccountId || "").trim();
  const apiToken = String(sanitizedConfig.cfApiToken || "").trim();
  if (!accountId || !apiToken) {
    return {
      ...getCloudflareQuotaLimitProfile("free"),
      usageModel: normalizeCloudflareUsageModel("bundled"),
      override: ""
    };
  }
  try {
    const usageModel = await fetchCloudflareAccountUsageModel(accountId, apiToken);
    return resolveCloudflareQuotaPlanProfile({ usageModel });
  } catch {
    return {
      ...getCloudflareQuotaLimitProfile("free"),
      usageModel: normalizeCloudflareUsageModel("bundled"),
      override: ""
    };
  }
}

function buildKvTidyQuotaBudgetReason(quotaBudget = {}) {
  const safeBudget = isPlainObject(quotaBudget) ? quotaBudget : {};
  const writeLimit = Math.max(1, Math.floor(Number(safeBudget.writeLimit) || 0));
  const estimatedPutCount = Math.max(0, Math.floor(Number(safeBudget.estimatedPutCount) || 0));
  const estimatedRollbackWriteCount = Math.max(0, Math.floor(Number(safeBudget.estimatedRollbackWriteCount) || 0));
  const estimatedWorstCaseWriteCount = Math.max(0, Math.floor(Number(safeBudget.estimatedWorstCaseWriteCount) || 0));
  const exceededBy = Math.max(0, estimatedWorstCaseWriteCount - writeLimit);
  const planLabel = String(safeBudget.planLabel || "").trim() || "FREE";
  const periodLabel = String(safeBudget.periodLabel || "").trim() || "今日";
  if (estimatedWorstCaseWriteCount <= writeLimit) return "";
  return `KV 整理已拦截：当前 ${planLabel} 计划 · ${periodLabel} 写入上限为 ${formatCount(writeLimit)}，本次预计写入 ${formatCount(estimatedPutCount)} 次，最坏回滚写回 ${formatCount(estimatedRollbackWriteCount)} 次，最坏共 ${formatCount(estimatedWorstCaseWriteCount)} 次，超出 ${formatCount(exceededBy)} 次。`;
}

function buildKvTidyQuotaBudgetWarning(quotaBudget = {}) {
  const safeBudget = isPlainObject(quotaBudget) ? quotaBudget : {};
  const planLabel = String(safeBudget.planLabel || "").trim() || "FREE";
  const periodLabel = String(safeBudget.periodLabel || "").trim() || "今日";
  const writeLimit = Math.max(1, Math.floor(Number(safeBudget.writeLimit) || 0));
  const estimatedPutCount = Math.max(0, Math.floor(Number(safeBudget.estimatedPutCount) || 0));
  const estimatedDeleteCount = Math.max(0, Math.floor(Number(safeBudget.estimatedDeleteCount) || 0));
  const estimatedRollbackWriteCount = Math.max(0, Math.floor(Number(safeBudget.estimatedRollbackWriteCount) || 0));
  const estimatedWorstCaseWriteCount = Math.max(0, Math.floor(Number(safeBudget.estimatedWorstCaseWriteCount) || 0));
  return `KV 配额预算：${planLabel} 计划 · ${periodLabel}，预计 put ${formatCount(estimatedPutCount)} 次，delete ${formatCount(estimatedDeleteCount)} 次，最坏回滚写回 ${formatCount(estimatedRollbackWriteCount)} 次，最坏写入 ${formatCount(estimatedWorstCaseWriteCount)} / ${formatCount(writeLimit)}。`;
}

function getCloudflareQuotaPeriodContext(planClass = "free", now = new Date()) {
  const normalizedPlanClass = String(planClass || "").trim().toLowerCase() === "paid" ? "paid" : "free";
  const safeNow = now instanceof Date ? new Date(now.getTime()) : new Date(now || Date.now());
  const nowIso = safeNow.toISOString();
  if (normalizedPlanClass === "paid") {
    const startDate = new Date(Date.UTC(safeNow.getUTCFullYear(), safeNow.getUTCMonth(), 1, 0, 0, 0, 0));
    const nextDate = new Date(Date.UTC(safeNow.getUTCFullYear(), safeNow.getUTCMonth() + 1, 1, 0, 0, 0, 0));
    return {
      planClass: normalizedPlanClass,
      periodLabel: "本月",
      startIso: startDate.toISOString(),
      endIso: nowIso,
      resetAtIso: nextDate.toISOString(),
      cacheBucketKey: `${safeNow.getUTCFullYear()}-${String(safeNow.getUTCMonth() + 1).padStart(2, "0")}`
    };
  }
  const startDate = new Date(Date.UTC(safeNow.getUTCFullYear(), safeNow.getUTCMonth(), safeNow.getUTCDate(), 0, 0, 0, 0));
  const nextDate = new Date(Date.UTC(safeNow.getUTCFullYear(), safeNow.getUTCMonth(), safeNow.getUTCDate() + 1, 0, 0, 0, 0));
  return {
    planClass: normalizedPlanClass,
    periodLabel: "今日",
    startIso: startDate.toISOString(),
    endIso: nowIso,
    resetAtIso: nextDate.toISOString(),
    cacheBucketKey: startDate.toISOString().slice(0, 10)
  };
}

function buildCloudflareRuntimeInFlightKey(parts = []) {
  return (Array.isArray(parts) ? parts : [parts]).map(item => String(item || "").trim()).filter(Boolean).join(":");
}

async function runCloudflareRuntimeDeduped(key, loader) {
  const dedupeKey = String(key || "").trim();
  if (!dedupeKey || typeof loader !== "function") return await loader();
  const existingTask = GLOBALS.CfRuntimeInFlight.get(dedupeKey);
  if (existingTask) return await existingTask;
  const nextTask = Promise.resolve()
    .then(() => loader())
    .finally(() => {
      if (GLOBALS.CfRuntimeInFlight.get(dedupeKey) === nextTask) {
        GLOBALS.CfRuntimeInFlight.delete(dedupeKey);
      }
    });
  GLOBALS.CfRuntimeInFlight.set(dedupeKey, nextTask);
  return await nextTask;
}

function trimCloudflareRuntimeErrorMessage(error, fallbackText = "cloudflare_runtime_error") {
  const message = String(error?.message || error || fallbackText).trim();
  return message.replace(/\s+/g, " ").slice(0, 240) || fallbackText;
}

function formatCloudflareQuotaValue(value, kind = "count") {
  if (kind === "bytes") return formatBytes(Math.max(0, Number(value) || 0));
  return formatCount(value);
}

function formatCloudflareCacheAgeText(cachedAtMs = 0, referenceNowMs = nowMs()) {
  const cachedAt = Math.max(0, Number(cachedAtMs) || 0);
  const currentMs = Math.max(cachedAt, Number(referenceNowMs) || nowMs());
  if (cachedAt <= 0) return "";
  const ageMs = Math.max(0, currentMs - cachedAt);
  if (ageMs < 60 * 1000) return "缓存年龄：不到 1 分钟";
  if (ageMs < 60 * 60 * 1000) return `缓存年龄：${Math.max(1, Math.round(ageMs / (60 * 1000)))} 分钟`;
  return `缓存年龄：${Math.max(1, Math.round(ageMs / (60 * 60 * 1000)))} 小时`;
}

function buildCloudflareQuotaMetricRow({ key = "", label = "", used = 0, limit = 0, kind = "count" } = {}) {
  const usedValue = Math.max(0, Number(used) || 0);
  const limitValue = Math.max(0, Number(limit) || 0);
  const rawPercent = limitValue > 0 ? usedValue / limitValue * 100 : 0;
  const percent = clampCloudflareQuotaPercent(rawPercent);
  return {
    key: String(key || "").trim(),
    label: String(label || "").trim(),
    usedValue,
    limitValue,
    usedText: formatCloudflareQuotaValue(usedValue, kind),
    limitText: formatCloudflareQuotaValue(limitValue, kind),
    percent,
    percentText: `${percent % 1 === 0 ? Math.round(percent) : percent}%`,
    tone: getCloudflareQuotaMetricTone(rawPercent),
    rawPercent
  };
}

function collectCloudflareQuotaExceededMetricLabels(metrics = []) {
  return (Array.isArray(metrics) ? metrics : [])
    .filter(metric => Number(metric?.rawPercent) > 100)
    .map(metric => String(metric?.label || "").trim())
    .filter(Boolean);
}

function buildCloudflareRuntimeQuotaCardPayload(raw = {}, defaults = {}) {
  const metrics = (Array.isArray(raw.metrics) ? raw.metrics : []).map(metric => ({
    key: String(metric?.key || "").trim(),
    label: String(metric?.label || "").trim(),
    usedText: String(metric?.usedText || "").trim(),
    limitText: String(metric?.limitText || "").trim(),
    percent: clampCloudflareQuotaPercent(metric?.percent),
    percentText: String(metric?.percentText || `${clampCloudflareQuotaPercent(metric?.percent)}%`).trim(),
    tone: String(metric?.tone || "slate").trim() || "slate"
  })).filter(metric => metric.key && metric.label);
  return {
    title: String(raw.title || defaults.title || "Cloudflare").trim() || "Cloudflare",
    status: String(raw.status || defaults.status || "idle").trim() || "idle",
    summary: String(raw.summary || defaults.summary || "暂无运行记录").trim() || "暂无运行记录",
    detail: String(raw.detail || defaults.detail || "").trim(),
    lines: (Array.isArray(raw.lines) ? raw.lines : Array.isArray(defaults.lines) ? defaults.lines : []).map(item => String(item || "").trim()).filter(Boolean),
    planLabel: String(raw.planLabel || defaults.planLabel || "").trim(),
    periodLabel: String(raw.periodLabel || defaults.periodLabel || "").trim(),
    resourceLabel: String(raw.resourceLabel || defaults.resourceLabel || "").trim(),
    metrics
  };
}

function buildCloudflareRuntimeQuotaSkippedCard(title = "", summary = "", detail = "") {
  return buildCloudflareRuntimeQuotaCardPayload({
    title,
    status: "skipped",
    summary,
    detail
  });
}

function buildCloudflareRuntimeQuotaFailedCard(title = "", summary = "", detail = "") {
  return buildCloudflareRuntimeQuotaCardPayload({
    title,
    status: "failed",
    summary,
    detail
  });
}

function buildCloudflareUsageAlertMessage(resourceTitle = "", card = {}, thresholdPercent = 0, matchedMetrics = []) {
  const safeThreshold = Math.max(1, Math.min(100, Math.round(Number(thresholdPercent) || 0)));
  /** @type {{ resourceLabel?: string, planLabel?: string, periodLabel?: string, status?: string }} */
  const safeCard = card && typeof card === "object" ? card : {};
  const safeMetrics = (Array.isArray(matchedMetrics) ? matchedMetrics : [])
    .map(metric => ({
      label: String(metric?.label || "").trim(),
      percentText: String(metric?.percentText || `${clampCloudflareQuotaPercent(metric?.percent)}%`).trim()
    }))
    .filter(metric => metric.label);
  const resourceLabel = String(safeCard.resourceLabel || "").trim() || String(resourceTitle || "").trim();
  const planLabel = String(safeCard.planLabel || "").trim();
  const periodLabel = String(safeCard.periodLabel || "").trim();
  const scopeParts = [resourceLabel];
  const tagParts = [planLabel, periodLabel].filter(Boolean);
  if (tagParts.length > 0) scopeParts.push(`（${tagParts.join(" / ")}）`);
  const metricText = safeMetrics.map(metric => `${metric.label} ${metric.percentText}`).join("、");
  const staleSuffix = String(safeCard.status || "").trim().toLowerCase() === "partial_failure"
    ? "（使用缓存数据）"
    : "";
  return `${String(resourceTitle || "Cloudflare").trim() || "Cloudflare"} 使用量达到阈值：${scopeParts.join("")}，${metricText}（阈值 ${safeThreshold}%）${staleSuffix}`;
}

function getDailyTelegramMetricPercentText(metrics = [], acceptedKeys = []) {
  const normalizedKeys = new Set((Array.isArray(acceptedKeys) ? acceptedKeys : [acceptedKeys]).map(key => String(key || "").trim()).filter(Boolean));
  for (const metric of Array.isArray(metrics) ? metrics : []) {
    const metricKey = String(metric?.key || "").trim();
    if (!normalizedKeys.has(metricKey)) continue;
    const percentText = String(metric?.percentText || "").trim();
    if (percentText) return percentText;
    if (metric?.percent !== undefined && metric?.percent !== null) return `${clampCloudflareQuotaPercent(metric.percent)}%`;
  }
  return "暂不可用";
}

function buildDailyTelegramSummaryMessage(summary = {}, scheduleContext = {}) {
  /** @type {{ zoneName?: string, requestCountDisplay?: string, requestSourceText?: string, todayTraffic?: string, trafficSourceText?: string, playCount?: number, infoCount?: number, nodeCount?: number, todayRequests?: number | null }} */
  const safeSummary = summary && typeof summary === "object" ? summary : {};
  /** @type {{ offsetLabel?: string, dateKey?: string }} */
  const safeContext = scheduleContext && typeof scheduleContext === "object" ? scheduleContext : {};
  const requestCountDisplay = String(safeSummary.requestCountDisplay || "").trim()
    || (safeSummary.todayRequests === null || safeSummary.todayRequests === undefined
      ? "暂不可用"
      : String(Number(safeSummary.todayRequests) || 0));
  const todayTraffic = String(safeSummary.todayTraffic || "").trim() || "暂不可用";
  const playCount = Math.max(0, Number(safeSummary.playCount) || 0);
  const infoCount = Math.max(0, Number(safeSummary.infoCount) || 0);
  const dateSuffix = safeContext.dateKey ? ` (${safeContext.dateKey})` : "";
  const lines = [
    `📊 EMBY-PROXY每日报表${dateSuffix}`,
    "",
    `请求数: ${requestCountDisplay}`,
    `视频流量 (CF 总计): ${todayTraffic}`,
    `请求: 播放请求 ${formatCount(playCount)} 次 | 获取播放信息 ${formatCount(infoCount)} 次`,
    "#Cloudflare #Emby #日报"
  ];
  return lines
    .map(line => String(line || "").trim())
    .filter((line, index, array) => !(line === "" && (index === 0 || array[index - 1] === "")))
    .join("\n");
}

function getDailyTelegramReportMetricHeading(kind = "", metric = {}) {
  const normalizedKind = normalizeDailyTelegramReportKind(kind);
  const metricKey = String(metric?.key || "").trim();
  const commonLabels = {
    storage: "存储容量 (Capacity)"
  };
  if (metricKey in commonLabels) return commonLabels[metricKey];
  if ((normalizedKind === "kv" && metricKey === "read") || (normalizedKind === "d1" && metricKey === "rowsRead")) {
    return "读取操作 (Read)";
  }
  if ((normalizedKind === "kv" && metricKey === "write") || (normalizedKind === "d1" && metricKey === "rowsWritten")) {
    return "写入操作 (Write)";
  }
  const metricLabel = String(metric?.label || "").trim() || metricKey || "指标";
  const metricCode = metricKey ? metricKey.replace(/([A-Z])/g, "_$1").replace(/^_+/, "").toUpperCase() : "";
  return metricCode ? `${metricLabel} (${metricCode})` : metricLabel;
}

function buildDailyTelegramReportMessage(kind = "", card = {}, scheduleContext = {}) {
  const normalizedKind = normalizeDailyTelegramReportKind(kind);
  if (normalizedKind === "summary") {
    return buildDailyTelegramSummaryMessage(card, scheduleContext);
  }
  const normalizedQuotaKind = normalizedKind === "d1" ? "d1" : "kv";
  /** @type {{ status?: string, resourceLabel?: string, summary?: string, planLabel?: string, periodLabel?: string, detail?: string, metrics?: Array<{ key?: string, label?: string, usedText?: string, limitText?: string, percentText?: string }> }} */
  const safeCard = card && typeof card === "object" ? card : {};
  /** @type {{ offsetLabel?: string, dateKey?: string }} */
  const safeContext = scheduleContext && typeof scheduleContext === "object" ? scheduleContext : {};
  const kindTitle = normalizedQuotaKind === "d1" ? "D1 数据库每日消耗报告" : "KV 数据库每日消耗报告";
  const hashtag = normalizedQuotaKind === "d1" ? "#D1" : "#KV";
  const metrics = Array.isArray(safeCard.metrics) ? safeCard.metrics : [];
  const dateSuffix = safeContext.dateKey ? ` (${safeContext.dateKey})` : "";
  const planLabel = String(safeCard.planLabel || "").trim();
  const periodLabel = String(safeCard.periodLabel || "").trim();
  const quotaScopeText = planLabel || periodLabel
    ? `${planLabel || "未知"} 计划 X ${(periodLabel || "当前")}配额`
    : String(safeCard.summary || "").trim() || "暂不可用";
  const readPercentText = getDailyTelegramMetricPercentText(metrics, normalizedQuotaKind === "d1" ? ["rowsRead", "read"] : ["read", "rowsRead"]);
  const writePercentText = getDailyTelegramMetricPercentText(metrics, normalizedQuotaKind === "d1" ? ["rowsWritten", "write"] : ["write", "rowsWritten"]);
  const storagePercentText = getDailyTelegramMetricPercentText(metrics, ["storage"]);
  const lines = [
    `📊 ${kindTitle}${dateSuffix}`,
    `配额口径：${quotaScopeText}`,
    `读取使用率：${readPercentText}`,
    `写入使用率：${writePercentText}`,
    `存储使用率：${storagePercentText}`,
    `#Cloudflare ${hashtag} #日报`
  ];
  return lines
    .map(line => String(line || "").trim())
    .filter((line, index, array) => !(line === "" && (index === 0 || array[index - 1] === "")))
    .join("\n");
}

const CLOUDFLARE_SUPPORTED_HTTP_PROXY_PORTS = new Set(["80", "8080", "8880", "2052", "2082", "2086", "2095"]);
const CLOUDFLARE_SUPPORTED_HTTPS_PROXY_PORTS = new Set(["443", "2053", "2083", "2087", "2096", "8443"]);
const CLOUDFLARE_CACHE_DISABLED_PROXY_PORTS = new Set(["2052", "2053", "2082", "2083", "2086", "2087", "2095", "2096", "8880", "8443"]);

function normalizePortText(value) {
  const trimmed = String(value ?? "").trim();
  if (!trimmed) return "";
  if (!/^\d{1,5}$/.test(trimmed)) return null;
  const port = Number(trimmed);
  if (!Number.isInteger(port) || port < 1 || port > 65535) return null;
  return String(port);
}

function getDefaultPortForProtocol(protocol) {
  if (protocol === "http:") return "80";
  if (protocol === "https:") return "443";
  return "";
}

function buildUrlAuthSegment(url) {
  const username = String(url?.username || "");
  const password = String(url?.password || "");
  if (!username && !password) return "";
  return `${username}${password ? `:${password}` : ""}@`;
}

function serializeUrlWithPort(url, portValue = "") {
  if (!(url instanceof URL)) return "";
  const protocol = String(url.protocol || "").trim().toLowerCase();
  if (!["http:", "https:"].includes(protocol)) return "";
  const normalizedPort = normalizePortText(portValue);
  if (normalizedPort === null) return "";
  const hostname = String(url.hostname || "").trim();
  if (!hostname) return "";
  const pathname = String(url.pathname || "/") || "/";
  const search = String(url.search || "");
  const hash = String(url.hash || "");
  return `${protocol}//${buildUrlAuthSegment(url)}${hostname}${normalizedPort ? `:${normalizedPort}` : ""}${pathname}${search}${hash}`.replace(/\/$/, "");
}

function serializeRelativeUrlLocation(url) {
  try {
    const parsedUrl = url instanceof URL
      ? new URL(url.toString())
      : new URL(String(url || ""), "https://relative-proxy.local/");
    const pathname = sanitizeProxyPath(parsedUrl.pathname || "/");
    return `${pathname}${String(parsedUrl.search || "")}${String(parsedUrl.hash || "")}`;
  } catch {
    return sanitizeProxyPath(String(url || "") || "/");
  }
}

function normalizeTargetUrlWithPort(targetValue, portValue = "", fallbackPort = "") {
  const rawTarget = String(targetValue || "").trim();
  if (!rawTarget) return null;
  try {
    const url = new URL(rawTarget);
    if (!["http:", "https:"].includes(url.protocol)) return null;
    const explicitPort = normalizePortText(url.port);
    const normalizedPort = normalizePortText(portValue);
    const normalizedFallbackPort = normalizePortText(fallbackPort);
    if (explicitPort === null || normalizedPort === null || normalizedFallbackPort === null) return null;
    const nextPort = explicitPort || normalizedPort || normalizedFallbackPort || getDefaultPortForProtocol(url.protocol);
    const serialized = serializeUrlWithPort(url, nextPort);
    return serialized || null;
  } catch {
    return null;
  }
}

function targetAuthorityHasExplicitPort(targetValue = "") {
  const rawTarget = String(targetValue || "").trim();
  if (!rawTarget) return false;
  try {
    const url = new URL(rawTarget);
    if (!["http:", "https:"].includes(url.protocol)) return false;
    const authorityMatch = rawTarget.match(/^[a-z][a-z0-9+.-]*:\/\/([^/?#]*)/i);
    if (!authorityMatch) return false;
    let authority = String(authorityMatch[1] || "");
    const authIndex = authority.lastIndexOf("@");
    if (authIndex >= 0) authority = authority.slice(authIndex + 1);
    if (!authority) return false;
    if (authority.startsWith("[")) {
      const ipv6EndIndex = authority.indexOf("]");
      if (ipv6EndIndex < 0) return false;
      return /^:\d+$/.test(authority.slice(ipv6EndIndex + 1));
    }
    return /:\d+$/.test(authority);
  } catch {
    return false;
  }
}

function targetNeedsDefaultPortCanonicalization(targetValue = "") {
  const rawTarget = String(targetValue || "").trim();
  if (!rawTarget) return false;
  try {
    const url = new URL(rawTarget);
    if (!["http:", "https:"].includes(url.protocol)) return false;
    return !targetAuthorityHasExplicitPort(rawTarget);
  } catch {
    return false;
  }
}

function getCloudflareSupportedProxyPorts(protocol) {
  return protocol === "https:"
    ? CLOUDFLARE_SUPPORTED_HTTPS_PROXY_PORTS
    : CLOUDFLARE_SUPPORTED_HTTP_PROXY_PORTS;
}

function inspectOriginTransportPort(protocol, portValue = "") {
  const normalizedProtocol = String(protocol || "").trim().toLowerCase();
  if (!["http:", "https:"].includes(normalizedProtocol)) return null;
  const normalizedPort = normalizePortText(portValue);
  if (normalizedPort === null) return null;

  const defaultPort = getDefaultPortForProtocol(normalizedProtocol);
  const effectivePort = normalizedPort || defaultPort;
  const protocolLabel = normalizedProtocol === "https:" ? "HTTPS" : "HTTP";
  const isDefaultPort = effectivePort === defaultPort;
  const isSupportedByCloudflareProxy = getCloudflareSupportedProxyPorts(normalizedProtocol).has(effectivePort);
  const isCacheDisabledByCloudflare = CLOUDFLARE_CACHE_DISABLED_PROXY_PORTS.has(effectivePort);

  if (isDefaultPort) {
    return {
      protocol: normalizedProtocol,
      port: effectivePort,
      isDefaultPort: true,
      isNonStandard: false,
      reverseProxyStatus: "ok",
      reverseProxyLabel: "反代可用",
      directStatus: "ok",
      directLabel: "直连可用",
      tone: "success",
      summary: `标准端口 ${effectivePort}：反代与直连通常都可用。`,
      detail: ""
    };
  }

  if (isSupportedByCloudflareProxy) {
    return {
      protocol: normalizedProtocol,
      port: effectivePort,
      isDefaultPort: false,
      isNonStandard: true,
      reverseProxyStatus: "ok",
      reverseProxyLabel: "反代可用",
      directStatus: "ok",
      directLabel: "直连可用",
      tone: isCacheDisabledByCloudflare ? "info" : "success",
      summary: `非标端口 ${effectivePort} 属于 Cloudflare 支持的 ${protocolLabel} 代理端口。`,
      detail: isCacheDisabledByCloudflare
        ? "如果源站域名走橙云，Worker 反代与浏览器直连通常都能使用，但 Cloudflare 默认不会缓存这个端口。"
        : "如果源站域名走橙云，Worker 反代与浏览器直连通常都能使用；若域名是灰云或其他 DNS，则按源站实际监听情况处理。"
    };
  }

  return {
    protocol: normalizedProtocol,
    port: effectivePort,
    isDefaultPort: false,
    isNonStandard: true,
    reverseProxyStatus: "conditional",
    reverseProxyLabel: "反代需灰云",
    directStatus: "conditional",
    directLabel: "直连需灰云",
    tone: "warning",
    summary: `非标端口 ${effectivePort} 不在 Cloudflare 默认支持的 ${protocolLabel} 代理端口内。`,
    detail: "如果源站域名走橙云，Cloudflare 通常不会代理这个端口，Worker 子请求可能忽略该端口，浏览器直连也可能失败；通常需要灰云直连、非 Cloudflare DNS，或使用 Spectrum。"
  };
}

function inspectOriginTransportTarget(targetValue = "", portValue = "") {
  const rawTarget = String(targetValue || "").trim();
  if (!rawTarget) return null;
  try {
    const url = new URL(rawTarget);
    if (!["http:", "https:"].includes(url.protocol)) return null;
    const normalizedPort = normalizePortText(portValue);
    if (normalizedPort === null) return null;
    const explicitPort = normalizePortText(url.port);
    if (explicitPort === null) return null;
    return inspectOriginTransportPort(url.protocol, explicitPort || normalizedPort || getDefaultPortForProtocol(url.protocol));
  } catch {
    return null;
  }
}

function toGraphQLString(value) {
  return JSON.stringify(String(value ?? ""));
}

function toGraphQLStringArray(values) {
  return JSON.stringify((Array.isArray(values) ? values : []).map(value => String(value ?? "")));
}

