  async getAuthFailureEntry(db, ip = "") {
    const normalizedIp = String(ip || "").trim();
    if (!normalizedIp || !db) return null;
    const ready = await this.ensureAuthFailuresTable(db);
    if (!ready) return null;
    try {
      const row = await db.prepare(`SELECT ip, fail_count, expires_at, updated_at
        FROM ${this.AUTH_FAILURES_TABLE}
        WHERE ip = ?
        LIMIT 1`).bind(normalizedIp).first();
      if (!row) return null;
      const expiresAt = Number(row?.expires_at ?? row?.expiresAt) || 0;
      if (expiresAt > 0 && expiresAt <= nowMs()) {
        await this.deleteAuthFailureEntry(db, normalizedIp).catch(() => false);
        return null;
      }
      return {
        ip: normalizedIp,
        failCount: Math.max(0, Number(row?.fail_count ?? row?.failCount) || 0),
        expiresAt,
        updatedAt: Number(row?.updated_at ?? row?.updatedAt) || 0
      };
    } catch (error) {
      logRuntimeFailure("auth_failures.read_failed", error, { ip: normalizedIp });
      return null;
    }
  },
  async upsertAuthFailureEntry(db, ip = "", entry = {}) {
    const normalizedIp = String(ip || "").trim();
    if (!normalizedIp || !db) return null;
    const ready = await this.ensureAuthFailuresTable(db);
    if (!ready) return null;
    const failCount = Math.max(0, Number(entry?.failCount) || 0);
    const expiresAt = Math.max(0, Number(entry?.expiresAt) || 0);
    const updatedAt = Math.max(0, Number(entry?.updatedAt) || nowMs());
    await db.prepare(`INSERT INTO ${this.AUTH_FAILURES_TABLE} (ip, fail_count, expires_at, updated_at)
      VALUES (?, ?, ?, ?)
      ON CONFLICT(ip) DO UPDATE SET
        fail_count = excluded.fail_count,
        expires_at = excluded.expires_at,
        updated_at = excluded.updated_at`).bind(
      normalizedIp,
      failCount,
      expiresAt,
      updatedAt
    ).run();
    return {
      ip: normalizedIp,
      failCount,
      expiresAt,
      updatedAt
    };
  },
